import collections

class SegmentTree:
    def __init__(self, size):
        self.size = size
        self.tree = [0] * (4 * size)

    def _update(self, node, start, end, idx, val):
        if start == end:
            self.tree[node] += val
            return

        mid = (start + end) // 2
        if start <= idx <= mid:
            self._update(2 * node, start, mid, idx, val)
        else:
            self._update(2 * node + 1, mid + 1, end, idx, val)

        self.tree[node] = self.tree[2 * node] + self.tree[2 * node + 1]

    def update(self, idx, val):
        self._update(1, 0, self.size - 1, idx, val)

    def _query(self, node, start, end, l, r):
        if r < start or end < l:
            return 0
        if l <= start and end <= r:
            return self.tree[node]

        mid = (start + end) // 2
        p1 = self._query(2 * node, start, mid, l, r)
        p2 = self._query(2 * node + 1, mid + 1, end, l, r)
        return p1 + p2

    def query(self, l, r):
        if l > r:
            return 0
        return self._query(1, 0, self.size - 1, l, r)

def countRangeSum(nums: list[int], lower: int, upper: int) -> int:
    n = len(nums)

    prefix_sums = [0] * (n + 1)
    for i in range(n):
        prefix_sums[i+1] = prefix_sums[i] + nums[i]

    all_values = set()
    for p_sum in prefix_sums:
        all_values.add(p_sum)
        all_values.add(p_sum - lower)
        all_values.add(p_sum - upper)

    sorted_unique_values = sorted(list(all_values))

    val_to_idx = {val: i for i, val in enumerate(sorted_unique_values)}

    compressed_size = len(sorted_unique_values)
    segment_tree = SegmentTree(compressed_size)

    count = 0

    segment_tree.update(val_to_idx[0], 1)

    for j in range(1, n + 1):
        current_sum = prefix_sums[j]

        query_lower_bound = current_sum - upper
        query_upper_bound = current_sum - lower

        compressed_l_idx = val_to_idx[query_lower_bound]
        compressed_r_idx = val_to_idx[query_upper_bound]

        count += segment_tree.query(compressed_l_idx, compressed_r_idx)

        segment_tree.update(val_to_idx[current_sum], 1)

    return count
